DECLARE @PaperID UNIQUEIDENTIFIER;
IF EXISTS (SELECT 1 FROM RESEARCH_PAPER WHERE DOI = N'https://doi.org/10.1017/s0140525x0999094x')
BEGIN
    SET @PaperID = (SELECT PaperID FROM RESEARCH_PAPER WHERE DOI = N'https://doi.org/10.1017/s0140525x0999094x');
    PRINT 'W2000196122: DOI already exists, skipping paper INSERT (using existing PaperID: ' + CAST(@PaperID AS NVARCHAR(36)) + ')';
    -- Still ensure journal/field links are updated
    IF @JournalID IS NOT NULL
        UPDATE RESEARCH_PAPER SET JournalID = @JournalID WHERE PaperID = @PaperID AND JournalID IS NULL;
    IF @FieldID IS NOT NULL
        UPDATE RESEARCH_PAPER SET FieldID = @FieldID WHERE PaperID = @PaperID AND FieldID IS NULL;
END
ELSE
BEGIN
    SET @PaperID = NEWID();
    INSERT INTO RESEARCH_PAPER (PaperID, SourceID, JournalID, FieldID, Title, Abstract, DOI, PubDate, PubYear, CitationCount, IsOpenAccess)
    VALUES (
        @PaperID,
        @SourceID,
        @JournalID,
        @FieldID,
        N'The myth of language universals: Language diversity and its importance for cognitive science',
        N'Talk of linguistic universals has given cognitive scientists the impression that languages are all built to a common pattern. In fact, there are vanishingly few universals of language in the direct sense that all languages exhibit them. Instead, diversity can be found at almost every level of linguistic organization. This fundamentally changes the object of enquiry from a cognitive science perspective. This target article summarizes decades of cross-linguistic work by typologists and descriptive linguists, showing just how few and unprofound the universal characteristics of language are, once we honestly confront the diversity offered to us by the world''s 6,000 to 8,000 languages. After surveying the various uses of "universal," we illustrate the ways languages vary radically in sound, meaning, and syntactic organization, and then we examine in more detail the core grammatical machinery of recursion, constituency, and grammatical relations. Although there are significant recurrent patterns in organization, these are better explained as stable engineering solutions satisfying multiple design constraints, reflecting both cultural-historical factors and the constraints of human cognition. Linguistic diversity then becomes the crucial datum for cognitive science: we are the only species with a communication system that is fundamentally variable at all levels. Recognizing the true extent of structural diversity in human language opens up exciting new research directions for cognitive scientists, offering thousands of different natural experiments given by different languages, with new opportunities for dialogue with biological paradigms concerned with change and diversity, and confronting us with the extraordinary plasticity of the highest human skills.',
        N'https://doi.org/10.1017/s0140525x0999094x',
        '2009-10-01',
        2009,
        2632,
        1
    );
END
GO

