-- [28/50] Executable UML: A Foundation for Model-Driven Architecture
-- OpenAlex: https://openalex.org/W1602736775
-- ───────────────────────────────────────────────────────────────

-- (no journal)
DECLARE @JournalID UNIQUEIDENTIFIER = NULL;
GO

-- 2. Research Field (upsert by FieldName)
DECLARE @FieldID UNIQUEIDENTIFIER;
