    INSERT INTO RESEARCH_PAPER (PaperID, SourceID, JournalID, FieldID, Title, Abstract, DOI, PubDate, PubYear, CitationCount, IsOpenAccess)
    VALUES (
        @PaperID,
        @SourceID,
        @JournalID,
        @FieldID,
        N'Functional Stages in the Formation of Human Long-Term Motor Memory',
        N'Previous research has demonstrated that the primate CNS has the ability to learn and store multiple and conflicting visuo-motor maps. Here we studied the ability of human subjects to learn to make reaching movements while interacting with one of two conflicting mechanical environments as produced by a robotic manipulandum. We demonstrate that two motor maps may be learned and retained, but only if the training sessions in the tasks are separated by an interval of approximately 5 hr. If the interval is shorter, learning of the second map begins with an internal model appropriate for the first task and performance in the second task is significantly impaired. Analysis of the after-effects suggests that with a short temporal distance, learning of the second task leads to an unlearning of the internal model for the first. With the longer temporal distance, learning of the second task starts with an unbiased internal model, and performance approaches that of naives. Furthermore, the memory of the consolidated skill lasts for at least 5 months after training. These results argue for a distinct change in the state of resistance of motor memory (to disruption) within a few hours after acquisition. We suggest that motor practice results in memories that have at least two functional components: soon after completion of practice, one component fades while another is strengthened. A further experiment suggests that the hypothetical first stage is not merely a gateway to long-term memory, but also temporary storage for items of information, whether new or old, for use in the near-term. Our results raise the possibility that there are distinct neuronal mechanisms for representation of the two functional stages of motor memory.',
        N'https://doi.org/10.1523/jneurosci.17-01-00409.1997',
        '1997-01-01',
        1997,
        726,
        1
    );
END
GO

