-- 3. Paper (skip if DOI exists)
DECLARE @PaperID UNIQUEIDENTIFIER;
IF EXISTS (SELECT 1 FROM RESEARCH_PAPER WHERE DOI = N'https://doi.org/10.1093/brain/awp135')
BEGIN
    SET @PaperID = (SELECT PaperID FROM RESEARCH_PAPER WHERE DOI = N'https://doi.org/10.1093/brain/awp135');
    PRINT 'W2145143840: DOI already exists, skipping paper INSERT (using existing PaperID: ' + CAST(@PaperID AS NVARCHAR(36)) + ')';
    -- Still ensure journal/field links are updated
    IF @JournalID IS NOT NULL
        UPDATE RESEARCH_PAPER SET JournalID = @JournalID WHERE PaperID = @PaperID AND JournalID IS NULL;
    IF @FieldID IS NOT NULL
        UPDATE RESEARCH_PAPER SET FieldID = @FieldID WHERE PaperID = @PaperID AND FieldID IS NULL;
END
ELSE
BEGIN
    SET @PaperID = NEWID();
    INSERT INTO RESEARCH_PAPER (PaperID, SourceID, JournalID, FieldID, Title, Abstract, DOI, PubDate, PubYear, CitationCount, IsOpenAccess)
    VALUES (
        @PaperID,
        @SourceID,
        @JournalID,
        @FieldID,
        N'The use of visual feedback, in particular mirror visual feedback, in restoring brain function',
        N'This article reviews the potential use of visual feedback, focusing on mirror visual feedback, introduced over 15 years ago, for the treatment of many chronic neurological disorders that have long been regarded as intractable such as phantom pain, hemiparesis from stroke and complex regional pain syndrome. Apart from its clinical importance, mirror visual feedback paves the way for a paradigm shift in the way we approach neurological disorders. Instead of resulting entirely from irreversible damage to specialized brain modules, some of them may arise from short-term functional shifts that are potentially reversible. If so, relatively simple therapies can be devised--of which mirror visual feedback is an example--to restore function.',
        N'https://doi.org/10.1093/brain/awp135',
        '2009-06-08',
        2009,
        713,
        1
    );
END
GO

