BEGIN
    SET @PaperID = (SELECT PaperID FROM RESEARCH_PAPER WHERE DOI = N'https://doi.org/10.1109/sp40001.2021.00019');
    PRINT 'W3154155772: DOI already exists, skipping paper INSERT (using existing PaperID: ' + CAST(@PaperID AS NVARCHAR(36)) + ')';
    -- Still ensure journal/field links are updated
    IF @JournalID IS NOT NULL
        UPDATE RESEARCH_PAPER SET JournalID = @JournalID WHERE PaperID = @PaperID AND JournalID IS NULL;
    IF @FieldID IS NOT NULL
        UPDATE RESEARCH_PAPER SET FieldID = @FieldID WHERE PaperID = @PaperID AND FieldID IS NULL;
END
ELSE
BEGIN
    SET @PaperID = NEWID();
    INSERT INTO RESEARCH_PAPER (PaperID, SourceID, JournalID, FieldID, Title, Abstract, DOI, PubDate, PubYear, CitationCount, IsOpenAccess)
    VALUES (
        @PaperID,
        @SourceID,
        @JournalID,
        @FieldID,
        N'Machine Unlearning',
        N'Once users have shared their data online, it is generally difficult for them to revoke access and ask for the data to be deleted. Machine learning (ML) exacerbates this problem because any model trained with said data may have memorized it, putting users at risk of a successful privacy attack exposing their information. Yet, having models unlearn is notoriously difficult.We introduce SISA training, a framework that expedites the unlearning process by strategically limiting the influence of a data point in the training procedure. While our framework is applicable to any learning algorithm, it is designed to achieve the largest improvements for stateful algorithms like stochastic gradient descent for deep neural networks. SISA training reduces the computational overhead associated with unlearning, even in the worst-case setting where unlearning requests are made uniformly across the training set. In some cases, the service provider may have a prior on the distribution of unlearning requests that will be issued by users. We may take this prior into account to partition and order data accordingly, and further decrease overhead from unlearning.Our evaluation spans several datasets from different domains, with corresponding motivations for unlearning. Under no distributional assumptions, for simple learning tasks, we observe that SISA training improves time to unlearn points from the Purchase dataset by 4.63×, and 2.45× for the SVHN dataset, over retraining from scratch. SISA training also provides a speed-up of 1.36× in retraining for complex learning tasks such as ImageNet classification; aided by transfer learning, this results in a small degradation in accuracy. Our work contributes to practical data governance in machine unlearning.',
        N'https://doi.org/10.1109/sp40001.2021.00019',
        '2021-05-01',
        2021,
        600,
        0
    );
END
GO

